// ─── NÚMEROS A LETRAS ─────────────────────────────────────────────────────────
const UNIDADES = ['','uno','dos','tres','cuatro','cinco','seis','siete','ocho','nueve',
  'diez','once','doce','trece','catorce','quince','dieciséis','diecisiete','dieciocho',
  'diecinueve','veinte','veintiuno','veintidós','veintitrés','veinticuatro','veinticinco',
  'veintiséis','veintisiete','veintiocho','veintinueve']
const DECENAS = ['','','','treinta','cuarenta','cincuenta','sesenta','setenta','ochenta','noventa']
const CENTENAS = ['','ciento','doscientos','trescientos','cuatrocientos','quinientos',
  'seiscientos','setecientos','ochocientos','novecientos']

function numLetras(n: number, genero: 'm' | 'f' | 'n' = 'n'): string {
  if (!isFinite(n) || n < 0) return '—'
  n = Math.floor(n)
  if (n === 0) return 'cero'
  if (n === 100) return 'cien'
  
  if (n === 1) {
    if (genero === 'm') return 'un'
    if (genero === 'f') return 'una'
    return 'uno'
  }
  if (n === 21) {
    if (genero === 'm') return 'veintiún'
    if (genero === 'f') return 'veintiuna'
    return 'veintiuno'
  }
  
  if (n < 30) return UNIDADES[n]
  
  if (n < 100) {
    const d = Math.floor(n/10), u = n%10
    if (u === 0) return DECENAS[d]
    let unidadStr = UNIDADES[u]
    if (u === 1) {
      if (genero === 'm') unidadStr = 'un'
      else if (genero === 'f') unidadStr = 'una'
      else unidadStr = 'uno'
    }
    return DECENAS[d] + ' y ' + unidadStr
  }
  
  if (n < 1000) {
    const c = Math.floor(n/100), r = n%100
    return r === 0 ? CENTENAS[c] : CENTENAS[c] + ' ' + numLetras(r, genero)
  }
  
  if (n < 1000000) {
    const m = Math.floor(n/1000), r = n%1000
    // Para miles, la cantidad de miles siempre se expresa en masculino (ej: veintiún mil)
    const base = m === 1 ? 'mil' : numLetras(m, 'm') + ' mil'
    return r === 0 ? base : base + ' ' + numLetras(r, genero)
  }
  
  return String(n)
}

// Capitaliza primera letra
function cap(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1)
}

// Metros a letras: "547,63 m – Quinientos cuarenta y siete metros, sesenta y tres centímetros"
function metrosLetras(metros: number): string {
  const entero = Math.floor(metros)
  const dec = Math.round((metros - entero) * 100)
  let texto = cap(numLetras(entero, 'm')) + (entero === 1 ? ' metro' : ' metros')
  if (dec > 0) texto += ', ' + numLetras(dec, 'm') + (dec === 1 ? ' centímetro' : ' centímetros')
  return texto
}

// Ángulo a letras: "90°00' – Noventa grados, cero minutos"
function anguloLetras(g: number, m: number): string {
  return cap(numLetras(g, 'm')) + (g === 1 ? ' grado' : ' grados') + ', ' + numLetras(m, 'm') + (m === 1 ? ' minuto' : ' minutos')
}

// Superficie en ha/a/ca a letras
function superficieHaLetras(m2: number): string {
  const ha = Math.floor(m2 / 10000)
  const resto_a = (m2 - ha * 10000)
  const a = Math.floor(resto_a / 100)
  const ca = Math.round((resto_a - a * 100) * 100) / 100

  const ha_ent = Math.floor(ca)
  const ca_dec = Math.round((ca - ha_ent) * 100)

  let texto = ''
  if (ha > 0) texto += cap(numLetras(ha, 'f')) + (ha === 1 ? ' hectárea' : ' hectáreas')
  if (a > 0) texto += (texto ? ', ' : '') + numLetras(a, 'm') + (a === 1 ? ' área' : ' áreas')
  if (ca > 0) {
    const caStr = ca_dec > 0
      ? numLetras(ha_ent, 'f') + ' con ' + numLetras(ca_dec, 'f') + ' centiáreas'
      : numLetras(Math.round(ca), 'f') + (Math.round(ca) === 1 ? ' centiárea' : ' centiáreas')
    texto += (texto ? ' y ' : '') + caStr
  }
  return texto || 'cero centiáreas'
}

// Superficie en formato "42 Ha. 23 a. 38,66 ca."
function superficieHaFormato(m2: number): string {
  const ha = Math.floor(m2 / 10000)
  const resto = m2 - ha * 10000
  const a = Math.floor(resto / 100)
  const ca = Math.round((resto - a * 100) * 100) / 100
  const caStr = ca.toFixed(2).replace('.', ',')
  return `${ha} Ha. ${a} a. ${caStr} ca.`
}

// Rumbo a letras: "S 80°29' E → Sur ochenta grados, veintinueve minutos Este"
const CARDINALS: Record<string, string> = { N: 'Norte', S: 'Sur', E: 'Este', O: 'Oeste' }

function rumboLetras(q1: string, g: number, m: number, q2: string): string {
  return `${CARDINALS[q1] || q1} ${numLetras(g)} grados, ${numLetras(m)} minutos ${CARDINALS[q2] || q2}`
}

function rumboCorto(desig: string, q1: string, g: number, m: number, q2: string): string {
  if (!desig || !q1 || !g) return ''
  return `(${desig}): ${q1} ${g}°${String(m).padStart(2,'0')}' ${q2} – ${cap(rumboLetras(q1, g, m, q2))}.`
}

// ─── CÁLCULO GAUSS ────────────────────────────────────────────────────────────
type Lado = { desig: string; lado: string; ang_g: string; ang_m: string; ang_s: string }

type FilaCalculo = {
  desig: string; lado: number
  ai_g: number; ai_m: number; ai_s: number
  ac_g: number; ac_m: number; ac_s: number
  dx: number; dy: number; dx_c: number; dy_c: number
  x: number; y: number
  ai_v: number; ych: number; acv: number; sup: number
}

type Resultado = {
  filas: FilaCalculo[]
  perimetro: number
  error_x: number; error_y: number; error_total: number
  superficie_m2: number; superficie_ha: number
  sum_dx: number; sum_dy: number; sum_dxc: number; sum_dyc: number
}

function calcularPlanilla(lados: Lado[]): Resultado | null {
  const n = lados.length
  if (n < 3) return null

  const angDec = lados.map(l => {
    const g = parseFloat(l.ang_g) || 0
    const m = parseFloat(l.ang_m) || 0
    const s = parseFloat(l.ang_s) || 0
    return g + m / 60 + s / 3600
  })
  const ladoNum = lados.map(l => parseFloat(l.lado) || 0)
  const perimetro = ladoNum.reduce((a, b) => a + b, 0)

  const ych: number[] = new Array(n).fill(0)
  const acv: number[] = new Array(n).fill(0)
  ych[0] = angDec[0]
  acv[0] = ych[0] >= 360 ? ych[0] - 360 : ych[0]
  for (let i = 1; i < n; i++) {
    const prev = ych[i-1] >= 360 ? ych[i-1] - 360 : ych[i-1]
    const sum = prev + angDec[i]
    ych[i] = sum > 180 ? sum - 180 : sum + 180
    acv[i] = ych[i] >= 360 ? ych[i] - 360 : ych[i]
  }

  const dx_raw = ladoNum.map((b, i) => b === 0 ? 0 : Math.round(b * Math.cos(acv[i] * Math.PI / 180) * 100) / 100)
  const dy_raw = ladoNum.map((b, i) => b === 0 ? 0 : Math.round(b * Math.sin(acv[i] * Math.PI / 180) * 100) / 100)

  const sum_dx = dx_raw.reduce((a, b) => a + b, 0)
  const sum_dy = dy_raw.reduce((a, b) => a + b, 0)
  const error_x = Math.round(sum_dx * 10000) / 10000
  const error_y = Math.round(sum_dy * 10000) / 10000
  const error_total = Math.round(Math.sqrt(error_x ** 2 + error_y ** 2) * 10000) / 10000

  const dx_c = ladoNum.map((b, i) => b === 0 ? 0 : Math.round((dx_raw[i] - b * error_x / perimetro) * 100) / 100)
  const dy_c = ladoNum.map((b, i) => b === 0 ? 0 : Math.round((dy_raw[i] - b * error_y / perimetro) * 100) / 100)
  const sum_dxc = Math.round(dx_c.reduce((a, b) => a + b, 0) * 100) / 100
  const sum_dyc = Math.round(dy_c.reduce((a, b) => a + b, 0) * 100) / 100

  const X: number[] = new Array(n).fill(0)
  const Y: number[] = new Array(n).fill(0)
  X[0] = 0; Y[0] = 0
  for (let i = 1; i < n; i++) {
    X[i] = Math.round((X[i-1] + dx_c[i-1]) * 100) / 100
    Y[i] = Math.round((Y[i-1] + dy_c[i-1]) * 100) / 100
  }

  const sups: number[] = new Array(n).fill(0)
  for (let i = 0; i < n; i++) {
    const j = (i + 1) % n
    sups[i] = X[j] * Y[i] - X[i] * Y[j]
  }
  const superficie_m2 = Math.round(Math.abs(sups.reduce((a, b) => a + b, 0)) / 2 * 10000) / 10000
  const superficie_ha = Math.round(superficie_m2 / 10000 * 1000000) / 1000000

  function toGMS(dec: number) {
    const g = Math.floor(dec)
    const rem_m = (dec - g) * 60
    const m = Math.floor(rem_m)
    const s = Math.round((rem_m - m) * 60)
    return { g, m, s }
  }

  const filas: FilaCalculo[] = lados.map((l, i) => {
    const ai = { g: parseFloat(l.ang_g)||0, m: parseFloat(l.ang_m)||0, s: parseFloat(l.ang_s)||0 }
    const ac = toGMS(acv[i])
    return {
      desig: l.desig, lado: ladoNum[i],
      ai_g: ai.g, ai_m: ai.m, ai_s: ai.s,
      ac_g: ac.g, ac_m: ac.m, ac_s: ac.s,
      dx: dx_raw[i], dy: dy_raw[i],
      dx_c: dx_c[i], dy_c: dy_c[i],
      x: X[i], y: Y[i],
      ai_v: angDec[i], ych: Math.round(ych[i]*1000)/1000,
      acv: Math.round(acv[i]*1000)/1000, sup: Math.round(sups[i]*10000)/10000,
    }
  })

  return { filas, perimetro, error_x, error_y, error_total, superficie_m2, superficie_ha, sum_dx, sum_dy, sum_dxc, sum_dyc }
}

// ─── GENERAR WORD ─────────────────────────────────────────────────────────────
function b64ToUint8(b64: string): Uint8Array {
  const bin = atob(b64); const arr = new Uint8Array(bin.length)
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i)
  return arr
}

function r(v: number | string, dec = 2): string {
  if (typeof v === 'string') return v
  if (v === 0) return '0'
  return v.toFixed(dec)
}

type Campos = { propietario: string; ubicacion: string; profesional: string; parcela: string }
type Rumbo = { desig: string; q1: string; g: string; m: string; q2: string }

async function generarPlanillaWord(campos: Campos, calc: Resultado) {
  const PizZip = (await import('pizzip')).default
  const Docxtemplater = (await import('docxtemplater')).default
  const zip = new PizZip(b64ToUint8(PLANILLA_B64))
  const doc = new Docxtemplater(zip, {
    paragraphLoop: true, linebreaks: true,
    delimiters: { start: '{', end: '}' }, nullGetter: () => ''
  })

  const filas = calc.filas.map(f => ({
    desig: f.desig,
    lado:  r(f.lado),
    ai_g:  String(f.ai_g), ai_m: String(f.ai_m), ai_s: String(f.ai_s),
    ac_g:  String(f.ac_g), ac_m: String(f.ac_m), ac_s: String(f.ac_s),
    dx:    r(f.dx),   dy:    r(f.dy),
    dx_c:  r(f.dx_c), dy_c:  r(f.dy_c),
    x:     r(f.x),    y:     r(f.y),
    ai_v:  r(f.ai_v, 6), ych: r(f.ych, 3), acv: r(f.acv, 3),
    sup:   r(f.sup, 4),
  }))

  doc.render({
    propietario: campos.propietario, ubicacion: campos.ubicacion,
    profesional: campos.profesional, parcela: campos.parcela,
    perimetro:     r(calc.perimetro),
    error_x:       r(calc.error_x, 4),
    error_y:       r(calc.error_y, 4),
    error_total:   r(calc.error_total, 4),
    superficie_m2: r(calc.superficie_m2, 4),
    superficie_ha: r(calc.superficie_ha, 6),
    sum_dx:  r(calc.sum_dx),  sum_dy:  r(calc.sum_dy),
    sum_dxc: r(calc.sum_dxc), sum_dyc: r(calc.sum_dyc),
    filas,
  })
  return doc.getZip().generate({ type: 'uint8array' })
}

async function generarMemoriaWord(campos: Campos, calc: Resultado, rumbo: Rumbo) {
  const PizZip = (await import('pizzip')).default
  const Docxtemplater = (await import('docxtemplater')).default
  const zip = new PizZip(b64ToUint8(MEMORIA_B64))
  const doc = new Docxtemplater(zip, {
    paragraphLoop: true, linebreaks: true,
    delimiters: { start: '{', end: '}' }, nullGetter: () => ''
  })

  const rg = parseInt(rumbo.g) || 0
  const rm = parseInt(rumbo.m) || 0

  const lados = calc.filas
    .filter(f => f.lado > 0)
    .map(f => ({
      linea: `${f.desig}: ${f.lado.toFixed(2).replace('.', ',')} m – ${metrosLetras(f.lado)}.`
    }))

  const angulos = calc.filas
    .filter(f => f.lado > 0)
    .map(f => {
      const vertice = f.desig.split('-')[0] || f.desig
      const angFmt  = `${f.ai_g}°${String(f.ai_m).padStart(2, '0')}'`
      return { linea: `${vertice}: ${angFmt} – ${anguloLetras(f.ai_g, f.ai_m)}.` }
    })

  const sfmt   = superficieHaFormato(calc.superficie_m2)
  const sletras = cap(superficieHaLetras(calc.superficie_m2))

  doc.render({
    rumbo_linea: rumbo.desig && rumbo.q1 && rumbo.q2
      ? rumboCorto(rumbo.desig, rumbo.q1, rg, rm, rumbo.q2)
      : '—',
    lados,
    angulos,
    superficie_linea: `${sfmt} ${sletras}.`,
  })
  return doc.getZip().generate({ type: 'uint8array' })
}

function descargar(bytes: Uint8Array, nombre: string): Promise<void> {
  return new Promise((resolve) => {
    const blob = new Blob([bytes], { type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = nombre
    a.style.display = 'none'
    document.body.appendChild(a)
    a.click()
    // Delay revocation so browser has time to start the download
    setTimeout(() => {
      URL.revokeObjectURL(url)
      document.body.removeChild(a)
      resolve()
    }, 1000)
  })
}

