// ─── COMPONENTE ───────────────────────────────────────────────────────────────
export function SuperficieTab() {
  const [numLados, setNumLados] = useState<number | ''>('')
  const [lados, setLados] = useState<Lado[]>([])
  const [campos, setCampos] = useState({ propietario: '', ubicacion: '', profesional: '', parcela: '' })
  const [rumbo, setRumbo] = useState<Rumbo>({ desig: '', q1: 'S', g: '', m: '', q2: 'E' })
  const [calc, setCalc] = useState<Resultado | null>(null)
  const [error, setError] = useState('')
  const [generating, setGenerating] = useState(false)
  const [generatingPlanilla, setGeneratingPlanilla] = useState(false)
  const [generatingMemoria, setGeneratingMemoria] = useState(false)
  const [previewMemoria, setPreviewMemoria] = useState(false)

  // Calculadora de ángulos auxiliar
  const [angA, setAngA] = useState({ g: '', m: '', s: '' })
  const [angB, setAngB] = useState({ g: '', m: '', s: '' })
  const [calcOp, setCalcOp] = useState<'+' | '-'>('+')
  const [calcHistorial, setCalcHistorial] = useState<string[]>([])

  // Lógica de calculadora de ángulos auxiliar en tiempo real
  const gA = parseInt(angA.g) || 0
  const mA = parseInt(angA.m) || 0
  const sA = parseInt(angA.s) || 0
  const gB = parseInt(angB.g) || 0
  const mB = parseInt(angB.m) || 0
  const sB = parseInt(angB.s) || 0

  const secA = gA * 3600 + mA * 60 + sA
  const secB = gB * 3600 + mB * 60 + sB
  const secRes = calcOp === '+' ? secA + secB : secA - secB

  const absSec = Math.abs(secRes)
  const resG = Math.floor(absSec / 3600)
  const resM = Math.floor((absSec % 3600) / 60)
  const resS = Math.round(absSec % 60)
  const resSign = secRes < 0 ? '-' : ''

  const resultStr = `${resSign}${resG}° ${resM}' ${resS}"`

  let equivStr = ''
  if (secRes < 0) {
    const posSec = (secRes % (360 * 3600) + (360 * 3600)) % (360 * 3600)
    const posG = Math.floor(posSec / 3600)
    const posM = Math.floor((posSec % 3600) / 60)
    const posS = Math.round(posSec % 60)
    equivStr = `${posG}° ${posM}' ${posS}"`
  }

  const handleAgregarHistorial = () => {
    const opStr = `${gA}° ${mA}' ${sA}" ${calcOp} ${gB}° ${mB}' ${sB}" = ${resultStr}`
    if (calcHistorial.includes(opStr)) return
    setCalcHistorial(p => [opStr, ...p].slice(0, 5))
  }

  // Preparar puntos para la vista previa en SVG
  const prepareSvgData = () => {
    if (!calc) return null
    const points = calc.filas.map(f => ({ x: f.x, y: f.y }))
    const xs = points.map(p => p.x)
    const ys = points.map(p => p.y)
    const minX = Math.min(...xs)
    const maxX = Math.max(...xs)
    const minY = Math.min(...ys)
    const maxY = Math.max(...ys)
    const width = maxX - minX || 1
    const height = maxY - minY || 1
    const boxSize = 260
    const padding = 35
    const usableSize = boxSize - padding * 2
    const scale = Math.min(usableSize / width, usableSize / height)
    const projected = points.map(p => {
      const cx = (p.x - minX - width / 2) * scale + boxSize / 2
      const cy = -(p.y - minY - height / 2) * scale + boxSize / 2
      return { x: cx, y: cy }
    })
    const pointsStr = projected.map(p => `${p.x},${p.y}`).join(' ')
    const labels = projected.map((p, i) => {
      const dx = p.x - boxSize / 2
      const dy = p.y - boxSize / 2
      const len = Math.sqrt(dx * dx + dy * dy) || 1
      const labelX = p.x + (dx / len) * 12
      const labelY = p.y + (dy / len) * 12 + 4
      const name = calc.filas[i].desig.split('-')[0] || String(i + 1)
      return { x: labelX, y: labelY, name }
    })
    return { pointsStr, labels, projected, boxSize }
  }

  const svgData = prepareSvgData()

  function handleSetLados(n: number) {
    if (n < 3 || n > 30) return
    setNumLados(n)
    const labels = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('')
    setLados(Array.from({ length: n }, (_, i) => ({
      desig: `${labels[i]}-${labels[(i + 1) % n]}`,
      lado: '', ang_g: '', ang_m: '', ang_s: '',
    })))
    setCalc(null); setError('')
  }

  function updateLado(i: number, field: keyof Lado, value: string) {
    setLados(prev => prev.map((l, idx) => idx === i ? { ...l, [field]: value } : l))
  }

  function handleCalcular() {
    setError('')
    for (let i = 0; i < lados.length; i++) {
      if (!lados[i].lado || parseFloat(lados[i].lado) <= 0) {
        setError(`El lado ${lados[i].desig} no tiene longitud válida.`); return
      }
      if (!lados[i].ang_g) {
        setError(`Falta el ángulo del vértice ${lados[i].desig.split('-')[0]}.`); return
      }
    }
    const resultado = calcularPlanilla(lados)
    if (!resultado) { setError('Error en el cálculo.'); return }
    setCalc(resultado)
  }

  async function handleDescargarTodo() {
    if (!calc) return
    setGenerating(true)
    setError('')
    try {
      const base = campos.propietario ? campos.propietario.replace(/\s+/g,'_') : 'Planilla'
      // Generate and download planilla first
      const planillaBytes = await generarPlanillaWord(campos, calc)
      await descargar(planillaBytes, `${base}_Coordenadas.docx`)
      // Then generate and download memoria
      const memoriaBytes = await generarMemoriaWord(campos, calc, rumbo)
      await descargar(memoriaBytes, `${base}_Memoria.docx`)
    } catch(e: any) {
      const msg = e?.properties?.errors?.map((err: any) => err.message).join(', ') || e?.message || String(e)
      setError('Error al generar archivos: ' + msg)
      console.error('Error generando DOCX:', e)
    } finally {
      setGenerating(false)
    }
  }

  async function handleDescargarPlanilla() {
    if (!calc) return
    setGeneratingPlanilla(true)
    setError('')
    try {
      const base = campos.propietario ? campos.propietario.replace(/\s+/g,'_') : 'Planilla'
      const bytes = await generarPlanillaWord(campos, calc)
      await descargar(bytes, `${base}_Coordenadas.docx`)
    } catch(e: any) {
      const msg = e?.properties?.errors?.map((err: any) => err.message).join(', ') || e?.message || String(e)
      setError('Error al generar planilla: ' + msg)
      console.error('Error planilla:', e)
    } finally {
      setGeneratingPlanilla(false)
    }
  }

  async function handleDescargarMemoria() {
    if (!calc) return
    setGeneratingMemoria(true)
    setError('')
    try {
      const base = campos.propietario ? campos.propietario.replace(/\s+/g,'_') : 'Planilla'
      const bytes = await generarMemoriaWord(campos, calc, rumbo)
      await descargar(bytes, `${base}_Memoria.docx`)
    } catch(e: any) {
      const msg = e?.properties?.errors?.map((err: any) => err.message).join(', ') || e?.message || String(e)
      setError('Error al generar memoria: ' + msg)
      console.error('Error memoria:', e)
    } finally {
      setGeneratingMemoria(false)
    }
  }

  const cierreOk = calc ? calc.error_total < 0.05 : false
  const rumboPreview = rumbo.desig && rumbo.q1 && rumbo.g && rumbo.q2
    ? rumboCorto(rumbo.desig, rumbo.q1, parseInt(rumbo.g)||0, parseInt(rumbo.m)||0, rumbo.q2)
    : null

  return (
    <div style={{ maxWidth: '1200px', width: '100%', margin: '0 auto' }} className="grid grid-cols-1 lg:grid-cols-12 gap-6">
      <div className="lg:col-span-8">
        <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Calculator className="h-5 w-5" />
            Cálculo de Coordenadas y Superficies
          </CardTitle>
          <p style={{ fontSize: '13px', color: 'var(--color-text-secondary)', marginTop: '4px' }}>
            Método de Gauss · Genera Planilla de Coordenadas + Memoria de las Operaciones
          </p>
        </CardHeader>
        <CardContent>
          {error && <div style={S.errorBox}>{error}</div>}

          {/* Datos del trabajo */}
          <div style={S.sectionTitle}>Datos del trabajo</div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-4">
            {[
              { key: 'propietario', label: 'Propietario' },
              { key: 'ubicacion', label: 'Ubicación' },
              { key: 'profesional', label: 'Profesional' },
              { key: 'parcela', label: 'N° de Parcela' },
            ].map(f => (
              <div key={f.key} style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                <Label style={{ fontSize: '13px' }}>{f.label}</Label>
                <Input value={(campos as any)[f.key]}
                  onChange={e => setCampos(p => ({ ...p, [f.key]: e.target.value }))}
                  placeholder={f.label} />
              </div>
            ))}
          </div>

          {/* RUMBO */}
          <div style={S.sectionTitle}>Rumbo inicial</div>
          <div className="overflow-x-auto hide-scrollbar w-full pb-2">
            <div style={{ display: 'grid', gridTemplateColumns: '110px 70px 80px 70px 70px', gap: '8px', alignItems: 'flex-end', minWidth: '420px' }}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                <Label style={{ fontSize: '12px' }}>Designación</Label>
                <Input value={rumbo.desig} onChange={e => setRumbo(p => ({...p, desig: e.target.value}))} placeholder="A-B" style={{ fontSize: '13px' }} />
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                <Label style={{ fontSize: '12px' }}>Cuadrante 1</Label>
                <Select value={rumbo.q1} onValueChange={v => setRumbo(p => ({...p, q1: v}))}>
                  <SelectTrigger style={{ fontSize: '13px' }}><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="N">N</SelectItem>
                    <SelectItem value="S">S</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                <Label style={{ fontSize: '12px' }}>Grados °</Label>
                <Input type="number" value={rumbo.g} onChange={e => setRumbo(p => ({...p, g: e.target.value}))} placeholder="83" min={0} max={90} style={{ fontSize: '13px', textAlign: 'right' }} />
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                <Label style={{ fontSize: '12px' }}>Minutos '</Label>
                <Input type="number" value={rumbo.m} onChange={e => setRumbo(p => ({...p, m: e.target.value}))} placeholder="16" min={0} max={59} style={{ fontSize: '13px', textAlign: 'right' }} />
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                <Label style={{ fontSize: '12px' }}>Cuadrante 2</Label>
                <Select value={rumbo.q2} onValueChange={v => setRumbo(p => ({...p, q2: v}))}>
                  <SelectTrigger style={{ fontSize: '13px' }}><SelectValue /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="E">E</SelectItem>
                    <SelectItem value="O">O</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>
          {rumboPreview && (
            <div style={{ background: '#E1F5EE', borderRadius: '8px', padding: '8px 12px', fontSize: '13px', color: '#0F6E56', marginBottom: '8px' }}>
              {rumboPreview}
            </div>
          )}

          {/* Polígono */}
          <div style={S.sectionTitle}>Polígono</div>
          <div style={{ display: 'flex', alignItems: 'flex-end', gap: '12px', marginBottom: '16px' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
              <Label style={{ fontSize: '13px' }}>Cantidad de lados (3–30)</Label>
              <Input type="number" min={3} max={30}
                value={numLados}
                onChange={e => setNumLados(e.target.value === '' ? '' : parseInt(e.target.value))}
                style={{ width: '120px' }}
                placeholder="Ej: 6" />
            </div>
            <Button
              onClick={() => typeof numLados === 'number' && handleSetLados(numLados)}
              disabled={!numLados || (numLados as number) < 3 || (numLados as number) > 30}
              style={{ background: '#0F6E56', color: 'white' }}
            >
              Crear tabla
            </Button>
          </div>

          {/* Tabla de entrada */}
          {lados.length > 0 && (
            <>
              <div style={S.sectionTitle}>Lados y ángulos interiores</div>
              <p style={{ fontSize: '12px', color: 'var(--color-text-secondary)', marginBottom: '10px' }}>
                ℹ️ El primer ángulo interior define el acimut inicial del polígono.
              </p>
              <div className="overflow-x-auto hide-scrollbar w-full pb-2">
                <div style={{ minWidth: '420px' }}>
                  <div style={{ display: 'grid', gridTemplateColumns: '110px 90px 70px 60px 60px', gap: '6px', marginBottom: '6px' }}>
                    {['Designacion', 'Lado (m)', 'Angulo', 'min', 'seg'].map(h => (
                      <div key={h} style={{ fontSize: '11px', fontWeight: '600', color: 'var(--color-text-secondary)', textAlign: 'center' }}>{h}</div>
                    ))}
                  </div>
                  {lados.map((l, i) => (
                    <div key={i} style={{ display: 'grid', gridTemplateColumns: '110px 90px 70px 60px 60px', gap: '6px', marginBottom: '6px', alignItems: 'center' }}>
                      <Input value={l.desig} onChange={e => updateLado(i, 'desig', e.target.value)}
                        style={{ fontSize: '13px', textAlign: 'center', fontWeight: '500' }} />
                      <Input type="number" value={l.lado} onChange={e => updateLado(i, 'lado', e.target.value)}
                        placeholder="0.00" style={{ fontSize: '13px', textAlign: 'right' }} />
                      <Input type="number" value={l.ang_g} onChange={e => updateLado(i, 'ang_g', e.target.value)}
                        placeholder="90" min={0} max={359} style={{ fontSize: '13px', textAlign: 'right' }} />
                      <Input type="number" value={l.ang_m} onChange={e => updateLado(i, 'ang_m', e.target.value)}
                        placeholder="0" min={0} max={59} style={{ fontSize: '13px', textAlign: 'right' }} />
                      <Input type="number" value={l.ang_s} onChange={e => updateLado(i, 'ang_s', e.target.value)}
                        placeholder="0" min={0} max={59} style={{ fontSize: '13px', textAlign: 'right' }} />
                    </div>
                  ))}
                </div>
              </div>
              <Button onClick={handleCalcular} style={{ background: '#0F6E56', color: 'white', marginTop: '12px', width: '100%' }}>
                <Calculator className="h-4 w-4 mr-2" />Calcular
              </Button>

              {/* RESULTADOS */}
              {calc && (
                <div style={S.resultBox}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' }}>
                    {cierreOk
                      ? <><CheckCircle style={{ width: '16px', height: '16px', color: '#1D9E75' }} /><span style={{ fontSize: '13px', color: '#1D9E75', fontWeight: '500' }}>Cierre aceptable</span></>
                      : <><AlertCircle style={{ width: '16px', height: '16px', color: '#D85A30' }} /><span style={{ fontSize: '13px', color: '#D85A30', fontWeight: '500' }}>Error de cierre elevado — revisar datos</span></>
                    }
                  </div>

                  {/* Grid para resultados y vista previa del polígono */}
                  <div className="grid grid-cols-1 md:grid-cols-12 gap-6 mt-6 mb-6">
                    {/* Columna Izquierda: Detalles de Superficie, Preview y Resumen */}
                    <div className="md:col-span-8">
                      {/* Superficie */}
                      <div style={{ background: '#E1F5EE', borderRadius: '10px', padding: '14px 16px', marginBottom: '14px', textAlign: 'center' }}>
                        <div style={{ fontSize: '12px', color: '#0F6E56', marginBottom: '4px' }}>SUPERFICIE</div>
                        <div style={{ fontSize: '26px', fontWeight: '600', color: '#0F6E56' }}>
                          {calc.superficie_m2.toLocaleString('es-AR', { minimumFractionDigits: 2, maximumFractionDigits: 4 })} m²
                        </div>
                        <div style={{ fontSize: '14px', color: '#0F6E56', marginTop: '2px' }}>
                          {superficieHaFormato(calc.superficie_m2)}
                        </div>
                        <div style={{ fontSize: '12px', color: '#0F6E56', marginTop: '4px', fontStyle: 'italic' }}>
                          {cap(superficieHaLetras(calc.superficie_m2))}
                        </div>
                      </div>

                      {/* Preview Memoria */}
                      <button
                        onClick={() => setPreviewMemoria(v => !v)}
                        style={{ fontSize: '12px', color: '#0F6E56', background: 'none', border: 'none', cursor: 'pointer', textDecoration: 'underline', marginBottom: '10px' }}
                      >
                        {previewMemoria ? '▲ Ocultar' : '▼ Ver'} preview de la Memoria
                      </button>

                      {previewMemoria && (
                        <div style={{ background: 'var(--color-background-primary)', border: '0.5px solid var(--color-border-tertiary)', borderRadius: '8px', padding: '14px', marginBottom: '12px', fontSize: '13px', lineHeight: '1.8' }}>
                          <strong>RUMBO:</strong><br />
                          {rumboPreview || '— (completá el rumbo arriba)'}<br /><br />
                          <strong>LADOS:</strong><br />
                          {calc.filas.map((f, i) => (
                            <span key={i} style={{ display: 'block' }}>
                              {f.desig}: {f.lado.toFixed(2).replace('.', ',')} m – {metrosLetras(f.lado)}.
                            </span>
                          ))}
                          <br />
                          <strong>ANGULOS:</strong><br />
                          {calc.filas.map((f, i) => (
                            <span key={i} style={{ display: 'block' }}>
                              {f.desig.split('-')[0]}: {f.ai_g}°{String(f.ai_m).padStart(2,'0')}' – {anguloLetras(f.ai_g, f.ai_m)}.
                            </span>
                          ))}
                          <br />
                          <strong>SUPERFICIE:</strong><br />
                          {superficieHaFormato(calc.superficie_m2)} {cap(superficieHaLetras(calc.superficie_m2))}.
                        </div>
                      )}

                      {/* Resumen */}
                      <div className="grid grid-cols-2 gap-x-8 mb-4">
                        <div>
                          {[
                            { label: 'Perímetro', value: `${calc.perimetro.toFixed(2)} m` },
                            { label: 'Error X', value: calc.error_x.toFixed(4) },
                            { label: 'Error Y', value: calc.error_y.toFixed(4) },
                            { label: 'Error total', value: calc.error_total.toFixed(4) },
                          ].map(item => (
                            <div key={item.label} style={S.lineRow}>
                              <span style={{ color: 'var(--color-text-secondary)' }}>{item.label}</span>
                              <span style={{ fontWeight: '500' }}>{item.value}</span>
                            </div>
                          ))}
                        </div>
                        <div>
                          {calc.filas.map((f, i) => (
                            <div key={i} style={S.lineRow}>
                              <span style={{ color: 'var(--color-text-secondary)' }}>{f.desig}</span>
                              <span style={{ fontWeight: '500' }}>Az. {f.ac_g}°{String(f.ac_m).padStart(2,'0')}'{String(f.ac_s).padStart(2,'0')}"</span>
                            </div>
                          ))}
                        </div>
                      </div>
                    </div>

                    {/* Columna Derecha: Croquis del Polígono en SVG */}
                    <div className="md:col-span-4 flex flex-col items-center justify-center p-4 rounded-xl border border-border" style={{ background: 'var(--color-background-primary)', minHeight: '300px' }}>
                      <div style={{ fontSize: '11px', fontWeight: '600', color: 'var(--color-text-secondary)', textTransform: 'uppercase', letterSpacing: '0.8px', marginBottom: '12px', width: '100%', textAlign: 'center' }}>
                        Croquis del Polígono
                      </div>
                      
                      {svgData ? (
                        <div style={{ position: 'relative', width: `${svgData.boxSize}px`, height: `${svgData.boxSize}px` }}>
                          <svg width={svgData.boxSize} height={svgData.boxSize} style={{ border: '0.5px dashed var(--color-border-tertiary)', borderRadius: '8px', background: 'var(--color-background-secondary)' }}>
                            <defs>
                              <pattern id="grid" width="20" height="20" patternUnits="userSpaceOnUse">
                                <path d="M 20 0 L 0 0 0 20" fill="none" stroke="var(--color-border-tertiary)" strokeWidth="0.5" strokeOpacity="0.3" />
                              </pattern>
                            </defs>
                            <rect width="100%" height="100%" fill="url(#grid)" />
                            
                            {/* Trazado del Polígono */}
                            <polygon
                              points={svgData.pointsStr}
                              fill="#10B981"
                              fillOpacity="0.08"
                              stroke="#0F6E56"
                              strokeWidth="2.5"
                              strokeLinejoin="round"
                            />
                            
                            {/* Vértices */}
                            {svgData.projected.map((p, i) => (
                              <circle
                                key={i}
                                cx={p.x}
                                cy={p.y}
                                r="4.5"
                                fill="#0F6E56"
                                stroke="white"
                                strokeWidth="1.5"
                              />
                            ))}
                            
                            {/* Etiquetas */}
                            {svgData.labels.map((l, i) => (
                              <text
                                key={i}
                                x={l.x}
                                y={l.y}
                                fontSize="11"
                                fontWeight="bold"
                                fill="#0F6E56"
                                textAnchor="middle"
                                style={{ userSelect: 'none' }}
                              >
                                {l.name}
                              </text>
                            ))}
                          </svg>

                          {/* Rosa de los Vientos */}
                          <div style={{ position: 'absolute', top: '10px', right: '10px', background: 'var(--color-background-primary)', padding: '4px 6px', borderRadius: '4px', display: 'flex', flexDirection: 'column', alignItems: 'center', fontSize: '9px', fontWeight: 'bold', color: '#0F6E56', border: '0.5px solid var(--color-border-tertiary)', userSelect: 'none' }}>
                            <span style={{ fontSize: '10px', lineHeight: '1' }}>▲</span>
                            <span>N</span>
                          </div>
                        </div>
                      ) : (
                        <div style={{ fontSize: '12px', color: 'var(--color-text-secondary)' }}>Sin datos gráficos</div>
                      )}
                    </div>
                  </div>

                  {/* Tabla */}
                  <div style={{ overflowX: 'auto' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '12px' }}>
                      <thead>
                        <tr style={{ borderBottom: '0.5px solid var(--color-border-tertiary)', background: 'var(--color-background-primary)' }}>
                          {['Lado', 'm', 'Δx corr.', 'Δy corr.', 'X', 'Y', 'Superficie'].map(h => (
                            <th key={h} style={{ padding: '6px 8px', textAlign: 'right', color: 'var(--color-text-secondary)', fontWeight: '500' }}>{h}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {calc.filas.map((f, i) => (
                          <tr key={i} style={{ borderBottom: '0.5px solid var(--color-border-tertiary)', background: i % 2 === 1 ? 'var(--color-background-secondary)' : undefined }}>
                            <td style={{ padding: '5px 8px', fontWeight: '500' }}>{f.desig}</td>
                            <td style={{ padding: '5px 8px', textAlign: 'right' }}>{f.lado.toFixed(2)}</td>
                            <td style={{ padding: '5px 8px', textAlign: 'right' }}>{f.dx_c.toFixed(2)}</td>
                            <td style={{ padding: '5px 8px', textAlign: 'right' }}>{f.dy_c.toFixed(2)}</td>
                            <td style={{ padding: '5px 8px', textAlign: 'right' }}>{f.x.toFixed(2)}</td>
                            <td style={{ padding: '5px 8px', textAlign: 'right' }}>{f.y.toFixed(2)}</td>
                            <td style={{ padding: '5px 8px', textAlign: 'right', color: f.sup > 0 ? '#1D9E75' : '#D85A30' }}>{f.sup.toFixed(4)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>

                  <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', marginTop: '16px' }}>
                    <Button
                      onClick={handleDescargarTodo}
                      disabled={generating || generatingPlanilla || generatingMemoria}
                      style={{ background: '#0F6E56', color: 'white', width: '100%' }}
                    >
                      <Download className="h-4 w-4 mr-2" />
                      {generating ? 'Generando…' : 'Descargar ambos archivos (Planilla + Memoria)'}
                    </Button>
                    <div style={{ display: 'flex', gap: '8px' }}>
                      <Button
                        onClick={handleDescargarPlanilla}
                        disabled={generating || generatingPlanilla || generatingMemoria}
                        variant="outline"
                        style={{ flex: 1, fontSize: '13px' }}
                      >
                        <Download className="h-4 w-4 mr-2" />
                        {generatingPlanilla ? 'Generando…' : 'Solo Planilla de Coordenadas'}
                      </Button>
                      <Button
                        onClick={handleDescargarMemoria}
                        disabled={generating || generatingPlanilla || generatingMemoria}
                        variant="outline"
                        style={{ flex: 1, fontSize: '13px' }}
                      >
                        <Download className="h-4 w-4 mr-2" />
                        {generatingMemoria ? 'Generando…' : 'Solo Memoria de Operaciones'}
                      </Button>
                    </div>
                  </div>
                  <p style={{ fontSize: '12px', color: 'var(--color-text-secondary)', marginTop: '8px', textAlign: 'center' }}>
                    Se generan documentos Word (.docx) compatibles con Microsoft Word
                  </p>
                </div>
              )}
            </>
          )}
        </CardContent>
      </Card>
      </div>

      <div className="lg:col-span-4">
        <Card>
          <CardHeader style={{ padding: '16px' }}>
            <CardTitle className="flex items-center gap-2" style={{ fontSize: '15px' }}>
              <Calculator className="h-4 w-4" style={{ color: '#0F6E56' }} />
              <span>Suma / Resta de Ángulos</span>
            </CardTitle>
            <p style={{ fontSize: '11px', color: 'var(--color-text-secondary)', marginTop: '2px' }}>
              Calculadora auxiliar de grados, minutos y segundos
            </p>
          </CardHeader>
          <CardContent style={{ padding: '16px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {/* Ángulo A */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
              <Label style={{ fontSize: '11px', fontWeight: '600' }}>Ángulo A</Label>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '4px' }}>
                <Input type="number" value={angA.g} onChange={e => setAngA(p => ({ ...p, g: e.target.value }))} placeholder="Grados °" min={0} style={{ fontSize: '12px', textAlign: 'right', padding: '6px' }} />
                <Input type="number" value={angA.m} onChange={e => setAngA(p => ({ ...p, m: e.target.value }))} placeholder="Minutos '" min={0} max={59} style={{ fontSize: '12px', textAlign: 'right', padding: '6px' }} />
                <Input type="number" value={angA.s} onChange={e => setAngA(p => ({ ...p, s: e.target.value }))} placeholder="Segundos" min={0} max={59} style={{ fontSize: '12px', textAlign: 'right', padding: '6px' }} />
              </div>
            </div>

            {/* Operación */}
            <div style={{ display: 'flex', justifyContent: 'center', gap: '8px' }}>
              <Button
                onClick={() => setCalcOp('+')}
                style={{
                  flex: 1,
                  height: '32px',
                  background: calcOp === '+' ? '#0F6E56' : 'transparent',
                  color: calcOp === '+' ? 'white' : 'var(--color-text-primary)',
                  border: '1px solid var(--color-border-primary)',
                  fontSize: '12px'
                }}
                variant="outline"
              >
                <Plus className="h-3.5 w-3.5 mr-1" /> Sumar
              </Button>
              <Button
                onClick={() => setCalcOp('-')}
                style={{
                  flex: 1,
                  height: '32px',
                  background: calcOp === '-' ? '#0F6E56' : 'transparent',
                  color: calcOp === '-' ? 'white' : 'var(--color-text-primary)',
                  border: '1px solid var(--color-border-primary)',
                  fontSize: '12px'
                }}
                variant="outline"
              >
                <Minus className="h-3.5 w-3.5 mr-1" /> Restar
              </Button>
            </div>

            {/* Ángulo B */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
              <Label style={{ fontSize: '11px', fontWeight: '600' }}>Ángulo B</Label>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '4px' }}>
                <Input type="number" value={angB.g} onChange={e => setAngB(p => ({ ...p, g: e.target.value }))} placeholder="Grados °" min={0} style={{ fontSize: '12px', textAlign: 'right', padding: '6px' }} />
                <Input type="number" value={angB.m} onChange={e => setAngB(p => ({ ...p, m: e.target.value }))} placeholder="Minutos '" min={0} max={59} style={{ fontSize: '12px', textAlign: 'right', padding: '6px' }} />
                <Input type="number" value={angB.s} onChange={e => setAngB(p => ({ ...p, s: e.target.value }))} placeholder="Segundos" min={0} max={59} style={{ fontSize: '12px', textAlign: 'right', padding: '6px' }} />
              </div>
            </div>

            {/* Botones de acción rápida */}
            <div style={{ display: 'flex', gap: '6px' }}>
              <Button
                onClick={handleAgregarHistorial}
                disabled={!angA.g && !angB.g}
                style={{ flex: 2, height: '32px', fontSize: '11px', background: '#0F6E56', color: 'white' }}
              >
                Guardar en Historial
              </Button>
              <Button
                onClick={() => {
                  setAngA({ g: '', m: '', s: '' })
                  setAngB({ g: '', m: '', s: '' })
                }}
                variant="ghost"
                style={{ flex: 1, height: '32px', fontSize: '11px', border: '1px solid var(--color-border-primary)' }}
              >
                Limpiar
              </Button>
            </div>

            {/* Resultado */}
            <div style={{ background: '#E1F5EE', border: '1px solid #C2EAD9', borderRadius: '8px', padding: '10px 12px', marginTop: '4px' }}>
              <div style={{ fontSize: '10px', color: '#0F6E56', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Resultado</div>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: '2px' }}>
                <span style={{ fontSize: '18px', fontWeight: '700', color: '#0F6E56' }}>
                  {resultStr}
                </span>
                <Button
                  onClick={() => navigator.clipboard.writeText(resultStr)}
                  variant="ghost"
                  style={{ height: '24px', width: '24px', padding: 0 }}
                  title="Copiar resultado"
                >
                  <Copy className="h-3.5 w-3.5" style={{ color: '#0F6E56' }} />
                </Button>
              </div>
              {equivStr && (
                <div style={{ fontSize: '10.5px', color: '#0F6E56', marginTop: '4px', opacity: 0.85, borderTop: '0.5px dashed #A3DCBF', paddingTop: '4px' }}>
                  Equivalente positivo: <strong>{equivStr}</strong>
                </div>
              )}
            </div>

            {/* Historial */}
            {calcHistorial.length > 0 && (
              <div style={{ marginTop: '6px', borderTop: '0.5px solid var(--color-border-primary)', paddingTop: '10px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '6px' }}>
                  <span style={{ fontSize: '11px', fontWeight: '600', color: 'var(--color-text-secondary)', display: 'flex', alignItems: 'center', gap: '4px' }}>
                    <History className="h-3 w-3" /> Historial
                  </span>
                  <button
                    onClick={() => setCalcHistorial([])}
                    style={{ fontSize: '10px', color: '#991B1B', background: 'none', border: 'none', cursor: 'pointer' }}
                  >
                    Limpiar todo
                  </button>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                  {calcHistorial.map((h, idx) => (
                    <div
                      key={idx}
                      style={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        fontSize: '11.5px',
                        padding: '4px 6px',
                        background: 'var(--color-background-secondary)',
                        borderRadius: '4px',
                        border: '0.5px solid var(--color-border-secondary)'
                      }}
                    >
                      <span style={{ fontFamily: 'monospace', color: 'var(--color-text-primary)' }}>{h}</span>
                      <button
                        onClick={() => {
                          try {
                            const match = h.match(/(\d+)°\s*(\d+)'\s*(\d+)"\s*([\+\-])\s*(\d+)°\s*(\d+)'\s*(\d+)"/)
                            if (match) {
                              setAngA({ g: match[1], m: match[2], s: match[3] })
                              setCalcOp(match[4] as '+' | '-')
                              setAngB({ g: match[5], m: match[6], s: match[7] })
                            }
                          } catch (e) {
                            console.error('Error parsing history:', e)
                          }
                        }}
                        style={{ fontSize: '10px', color: '#0F6E56', background: 'none', border: 'none', cursor: 'pointer', fontWeight: '500' }}
                        title="Cargar cálculo"
                      >
                        Cargar
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  )
}